func (a *adapter) MyUpsert(ctx context.Context, input appstripe.MyInput) error {
	if err := input.Validate(); err != nil {
		return models.NewGenericValidationError(fmt.Errorf("my upsert: %w", err))
	}
	return entutils.TransactingRepoWithNoValue(ctx, a, func(ctx context.Context, repo *adapter) error {
		err := repo.db.AppStripe.Update().Where(appstripedb.Namespace(input.AppID.Namespace)).Where(appstripedb.ID(input.AppID.ID)).Exec(ctx)
		if entdb.IsNotFound(err) { return app.NewAppNotFoundError(input.AppID) }
		return err
	})
}

func (c *stripeAppClient) MyOperation(ctx context.Context, input MyInput) (MyOutput, error) {
	if err := input.Validate(); err != nil { return MyOutput{}, models.NewGenericValidationError(err) }
	result, err := c.client.SomeResource.New(&stripe.SomeParams{Metadata: map[string]string{StripeMetadataNamespace: input.AppID.Namespace, StripeMetadataAppID: input.AppID.ID}})
	if err != nil { return MyOutput{}, c.providerError(err) }
	return MyOutput{ID: result.ID}, nil
}

func (h *handler) MyStripeAction() httptransport.HandlerWithArgs[MyReq, MyResp, MyParams] {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params MyParams) (MyReq, error) {
			ns, err := h.resolveNamespace(ctx); if err != nil { return MyReq{}, err }
			cus, err := h.customerService.GetCustomer(ctx, customer.GetCustomerInput{CustomerID: &customer.CustomerID{Namespace: ns, ID: params.CustomerID}})
			if err != nil { return MyReq{}, err }
			if cus != nil && cus.IsDeleted() { return MyReq{}, models.NewGenericPreConditionFailedError(fmt.Errorf("customer is deleted")) }
			return MyReq{CustomerID: cus.GetID()}, nil
		},
		func(ctx context.Context, req MyReq) (MyResp, error) { return h.service.MyAction(ctx, req) },
		commonhttp.JSONResponseEncoderWithStatus[MyResp](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("myStripeAction"))...,
	)
}

func (s *Service) MyAction(ctx context.Context, input appstripe.MyInput) (appstripe.MyOutput, error) {
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (appstripe.MyOutput, error) {
		out, err := s.adapter.MyAdapterOp(ctx, input)
		if err != nil { return appstripe.MyOutput{}, fmt.Errorf("my action: %w", err) }
		event := appstripe.NewMyActionEvent(ctx, input.Namespace, out.ID)
		if err := s.publisher.Publish(ctx, event); err != nil { return appstripe.MyOutput{}, fmt.Errorf("failed to publish event: %w", err) }
		return out, nil
	})
}
